#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        int *a = (int *)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) {
            scanf("%d", &a[i]);
        }
        int cnt = 0;
        for (int i = 0; i < N; ++i) {
            if (a[i] > a[(i + 1) % N]) ++cnt;
        }
        printf("%s\n", cnt <= 1 ? "true" : "false");
        free(a);
    }
    return 0;
}

