import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        a = [int(next(it)) for _ in range(N)]
        cnt = 0
        for i in range(N):
            if a[i] > a[(i + 1) % N]:
                cnt += 1
        out_lines.append('true' if cnt <= 1 else 'false')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

